#!/usr/bin/env bash
# pMMC Benchmark — 3-tool sequential comparison
# Generated by: pMMC-benchmark
# Runs 3D-GNOME, cudaMMC, and pMMC-reconstruct ONE AFTER ANOTHER on
# the same synthetic data so they never compete for resources.
#
# Usage:  bash run_benchmark.sh [output_dir]
#
# Environment variables (override paths):
#   PMMC_GENERATE — pMMC-generate     (default: pMMC-generate)
#   PMMC_EXE      — pMMC-reconstruct  (default: pMMC-reconstruct)
#   PMMC_ANALYZE  — pMMC-analyze       (default: pMMC-analyze)
#   CUDAMMC_EXE   — cudaMMC            (default: cudaMMC, optional)
#   GNOME_EXE     — 3D-GNOME           (default: 3dnome, optional)
set -euo pipefail

OUTDIR="${1:-./benchmark_results}"
PMMC_GENERATE="${PMMC_GENERATE:-pMMC-generate}"
PMMC_EXE="${PMMC_EXE:-pMMC-reconstruct}"
PMMC_ANALYZE="${PMMC_ANALYZE:-pMMC-analyze}"
CUDAMMC_EXE="${CUDAMMC_EXE:-cudaMMC}"
GNOME_EXE="${GNOME_EXE:-3dnome}"
CHR="chr22"
SEED=42
ENSEMBLE=20
CSV="$OUTDIR/benchmark_results.csv"

write_generate_ini() {
  cat > "$1" <<GENEOF
[main]
output_dir = $2
chromosomes = $3
label = synthetic
num_loops = $4
ensemble_size = ${5:-1}
resolution = 25000
seed = $SEED
GENEOF
}

write_reconstruct_ini() {
  cat > "$1" <<INIEOF
[main]
output_level = 1
random_walk = no
loop_density = 5
chromosomes = $5
output_dir = $3
label = $4
seed = $6
ensemble_size = ${7:-1}
output_format = pdb
max_level = 5
steps_lvl1 = 2
steps_lvl2 = 2
steps_arcs = 3
steps_smooth = 3
noise_lvl1 = 0.5
noise_lvl2 = 0.5
noise_arcs = 0.01
noise_smooth = 5.0
max_pet_length = 1000000
long_pet_power = 2.0
long_pet_scale = 1.0
[cuda]
num_threads = 512
blocks_multiplier = 4
milestone_fails = 3
[data]
data_dir = $2
anchors = anchors.txt
clusters = clusters.txt
factors = synthetic
singletons = singletons.txt
split_singleton_files_by_chr = no
singletons_inter =
segment_split = ${2}segments.bed
centromeres = ${2}centromeres.bed
[distance]
genomic_dist_power = 0.5
genomic_dist_scale = 1.0
genomic_dist_base = 0.0
freq_dist_scale = 25.0
freq_dist_power = -0.6
freq_dist_scale_inter = 120.0
freq_dist_power_inter = -1.0
count_dist_a = 0.2
count_dist_scale = 1.8
count_dist_shift = 8
count_dist_base_level = 0.2
[template]
template_scale = 7.0
dist_heatmap_scale = 15.0
[motif_orientation]
use_motif_orientation = no
weight = 50.0
[springs]
stretch_constant = 0.1
squeeze_constant = 0.1
angular_constant = 0.1
stretch_constant_arcs = 1.0
squeeze_constant_arcs = 1.0
[simulation_heatmap]
max_temp_heatmap = 5.0
delta_temp_heatmap = 0.9999
jump_temp_scale_heatmap = 50.0
jump_temp_coef_heatmap = 20.0
stop_condition_improvement_threshold_heatmap = 0.99
stop_condition_successes_threshold_heatmap = 10
stop_condition_steps_heatmap = 50000
[simulation_arcs]
max_temp = 5.0
delta_temp = 0.9999
jump_temp_scale = 50.0
jump_temp_coef = 20.0
stop_condition_improvement_threshold = 0.975
stop_condition_successes_threshold = 100
stop_condition_steps = 50000
[simulation_arcs_smooth]
dist_weight = 1.0
angle_weight = 1.0
max_temp = 5.0
delta_temp = 0.9999
jump_temp_scale = 50.0
jump_temp_coef = 20.0
stop_condition_improvement_threshold = 0.99
stop_condition_successes_threshold = 50
stop_condition_steps = 50000
INIEOF
}

mkdir -p "$OUTDIR"
echo "tool,chromosome,wall_time_seconds,exit_code" > "$CSV"

# Step 1 — generate synthetic data
echo "[1/5] Generating synthetic data..."
SYNTH="$OUTDIR/synthetic/"; mkdir -p "$SYNTH"
write_generate_ini "$OUTDIR/generate.ini" "$SYNTH" "$CHR" 100 "$ENSEMBLE"
"$PMMC_GENERATE" -s "$OUTDIR/generate.ini"

# Step 2 — 3D-GNOME (sequential)
if command -v "$GNOME_EXE" &>/dev/null; then
  echo "[2/5] Running 3D-GNOME..."
  D="$OUTDIR/3dgnome/"; mkdir -p "$D"
  write_reconstruct_ini "$D/settings.ini" "$SYNTH" "$D" gnome "$CHR" $SEED
  T0=$(date +%s%N)
  "$GNOME_EXE" -a create -s "$D/settings.ini" -c "$CHR" -o "$D" -n gnome && RC=0 || RC=$?
  T1=$(date +%s%N); T=$(echo "scale=3;($T1-$T0)/1000000000"|bc)
  echo "3D-GNOME,$CHR,$T,$RC" >> "$CSV"
else
  echo "[2/5] 3D-GNOME not found, skipping."
  echo "3D-GNOME,$CHR,,skipped" >> "$CSV"
fi

# Step 3 — cudaMMC (sequential)
if command -v "$CUDAMMC_EXE" &>/dev/null; then
  echo "[3/5] Running cudaMMC..."
  D="$OUTDIR/cudammc/"; mkdir -p "$D"
  write_reconstruct_ini "$D/settings.ini" "$SYNTH" "$D" cuda "$CHR" $SEED
  T0=$(date +%s%N)
  "$CUDAMMC_EXE" -a create -s "$D/settings.ini" -c "$CHR" -o "$D" -n cuda && RC=0 || RC=$?
  T1=$(date +%s%N); T=$(echo "scale=3;($T1-$T0)/1000000000"|bc)
  echo "cudaMMC,$CHR,$T,$RC" >> "$CSV"
else
  echo "[3/5] cudaMMC not found, skipping."
  echo "cudaMMC,$CHR,,skipped" >> "$CSV"
fi

# Step 4 — pMMC-reconstruct (sequential)
echo "[4/5] Running pMMC..."
D="$OUTDIR/pmmc/"; mkdir -p "$D"
write_reconstruct_ini "$D/settings.ini" "$SYNTH" "$D" pmmc "$CHR" $SEED
T0=$(date +%s%N)
"$PMMC_EXE" -s "$D/settings.ini" && RC=0 || RC=$?
T1=$(date +%s%N); T=$(echo "scale=3;($T1-$T0)/1000000000"|bc)
echo "pMMC,$CHR,$T,$RC" >> "$CSV"

# Step 5 — quality comparison
echo "[5/5] Computing quality metrics..."
M="$OUTDIR/metrics/"; mkdir -p "$M"
P="$OUTDIR/pmmc/loops_pmmc.hcm"
C="$OUTDIR/cudammc/loops_cuda.hcm"
G="$OUTDIR/3dgnome/loops_gnome.hcm"
for PAIR in "pmmc_vs_cuda:$P:$C" "pmmc_vs_gnome:$P:$G"; do
  NAME="${PAIR%%:*}"; REST="${PAIR#*:}"
  FA="${REST%%:*}"; FB="${REST#*:}"
  if [ -f "$FA" ] && [ -f "$FB" ]; then
    cat > "$M/${NAME}.ini" <<MEOF
[main]
action = metrics
output_dir = $M
label = $NAME
chromosomes = $CHR
level = 2
resolution = 25000
input_file_2 = $FB
[data]
input_file = $FA
MEOF
    "$PMMC_ANALYZE" -s "$M/${NAME}.ini" || true
  fi
done

echo ""
echo "Benchmark complete.  Results: $CSV"
cat "$CSV"
